async function loadOrbitalConfigurations(){const n=document.getElementById("orbital-configurations");if(n){n.innerHTML='<div class="orbital-loading">Loading server configurations...</div>';try{const n=window.ElementoI18n?.assetUrl?window.ElementoI18n.assetUrl("CMS/orbital.json"):"CMS/orbital.json",a=await fetch(n);if(!a.ok)throw new Error(`HTTP error! status: ${a.status}`);const s=await a.json(),i=window.ElementoI18n?window.ElementoI18n.getPageLocale():"en";renderOrbitalConfigurations(s.map(n=>window.ElementoI18n?window.ElementoI18n.resolveCmsEntry(n,i):n))}catch(a){console.error("Error loading orbital configurations:",a),n.innerHTML='\n            <div class="orbital-error">\n                <div class="orbital-error-icon">⚠️</div>\n                <h3>Error Loading Configurations</h3>\n                <p>Unable to load server configurations. Please try again later.</p>\n            </div>\n        '}}else console.error("Orbital configurations container not found")}function renderOrbitalConfigurations(n){const a=document.getElementById("orbital-configurations");if(!a||!n||0===n.length)return void(a.innerHTML='<div class="orbital-error">No configurations available</div>');const s=n.map(n=>`\n        <div class="orbital-config-card ${n.name.toLowerCase().includes("custom")?"custom-quote":""} fade-in">\n            <div class="orbital-config-header">\n                <h3 class="orbital-config-name">${n.name}</h3>\n                <p class="orbital-config-description">${n.description}</p>\n            </div>\n\n            <div class="orbital-config-specs">\n                <div class="orbital-spec-item">\n                    <span class="orbital-spec-label">CPU</span>\n                    <span class="orbital-spec-value">${n.specs.cpu}</span>\n                </div>\n                <div class="orbital-spec-item">\n                    <span class="orbital-spec-label">RAM</span>\n                    <span class="orbital-spec-value">${n.specs.ram}</span>\n                </div>\n                <div class="orbital-spec-item">\n                    <span class="orbital-spec-label">Storage</span>\n                    <span class="orbital-spec-value">${n.specs.storage}</span>\n                </div>\n                <div class="orbital-spec-item">\n                    <span class="orbital-spec-label">Network</span>\n                    <span class="orbital-spec-value">${n.specs.network}</span>\n                </div>\n                ${n.specs.gpu&&"None"!==n.specs.gpu?`\n                <div class="orbital-spec-item">\n                    <span class="orbital-spec-label">GPU</span>\n                    <span class="orbital-spec-value">${n.specs.gpu}</span>\n                </div>\n                `:""}\n            </div>\n\n            <div class="orbital-config-features">\n                <h4 class="orbital-features-title">Key Features</h4>\n                <ul class="orbital-features-list">\n                    ${n.features.map(n=>`\n                        <li class="orbital-feature-item">${n}</li>\n                    `).join("")}\n                </ul>\n            </div>\n\n            <div class="orbital-config-use-cases">\n                <h4 class="orbital-use-cases-title">Ideal For</h4>\n                <ul class="orbital-use-cases-list">\n                    ${n.use_cases.map(n=>`\n                        <li class="orbital-use-case-item">${n}</li>\n                    `).join("")}\n                </ul>\n            </div>\n\n            <div class="orbital-config-pricing">\n                <div class="orbital-pricing-monthly">\n                    <div class="price">${n.pricing.monthly}</div>\n                    <div class="period">per month</div>\n                </div>\n                <div class="orbital-pricing-setup">\n                    <div class="price">${n.pricing.setup}</div>\n                    <div class="label">setup fee</div>\n                </div>\n            </div>\n\n            <div class="orbital-config-availability">\n                <div class="orbital-availability-status ${n.availability.toLowerCase().replace(" ","-")}">\n                    <div class="orbital-availability-dot"></div>\n                    ${n.availability}\n                </div>\n            </div>\n\n            <div class="orbital-config-cta">\n                ${n.name.toLowerCase().includes("custom")?'<a href="contact.html" class="btn btn-primary">Get Custom Quote</a>':'<a href="contact.html" class="btn btn-primary">Request Quote</a>'}\n            </div>\n        </div>\n    `).join("");a.innerHTML=s;a.querySelectorAll(".orbital-config-card").forEach((n,a)=>{n.style.opacity="0",n.style.transform="translateY(20px)",setTimeout(()=>{n.style.transition="all 0.6s ease",n.style.opacity="1",n.style.transform="translateY(0)"},100*a)})}document.addEventListener("DOMContentLoaded",function(){loadOrbitalConfigurations()}),document.addEventListener("DOMContentLoaded",function(){document.querySelectorAll('a[href^="#"]').forEach(n=>{n.addEventListener("click",function(n){n.preventDefault();const a=this.getAttribute("href").substring(1),s=document.getElementById(a);s&&s.scrollIntoView({behavior:"smooth",block:"start"})})})});